<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Game - 24 Bots</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
            background: #0a0e27;
            color: #fff;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            padding: 20px;
        }

        .container {
            max-width: 500px;
            width: 100%;
        }

        h1 {
            margin-bottom: 20px;
            text-align: center;
            font-size: 28px;
            background: linear-gradient(135deg, #00ff88, #00ccff);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        #maze {
            display: block;
            margin: 0 auto 20px;
            background: #000;
            border: 3px solid #00ff88;
            box-shadow: 0 0 20px rgba(0, 255, 136, 0.3);
            width: 400px;
            height: 400px;
            image-rendering: pixelated;
        }

        .hud {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 15px;
            margin-bottom: 20px;
        }

        .hud-item {
            padding: 15px;
            background: linear-gradient(135deg, #1a2a4a, #0a1a3a);
            border: 2px solid #00ccff;
            border-radius: 8px;
            text-align: center;
        }

        .hud-label {
            font-size: 11px;
            color: #00ccff;
            text-transform: uppercase;
            letter-spacing: 1px;
            margin-bottom: 8px;
            opacity: 0.7;
        }

        .hud-value {
            font-size: 32px;
            font-weight: bold;
            color: #00ff88;
            font-family: 'Courier New', monospace;
        }

        #reset {
            width: 100%;
            padding: 14px;
            background: linear-gradient(135deg, #00ff88, #00dd77);
            color: #000;
            border: none;
            border-radius: 8px;
            font-size: 16px;
            font-weight: bold;
            cursor: pointer;
            transition: all 0.2s;
            box-shadow: 0 0 15px rgba(0, 255, 136, 0.3);
        }

        #reset:hover {
            background: linear-gradient(135deg, #00ff99, #00ee88);
            box-shadow: 0 0 25px rgba(0, 255, 136, 0.5);
            transform: translateY(-2px);
        }

        #reset:active {
            transform: translateY(0);
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>⚡ MAZE PURSUIT</h1>
        <canvas id="maze"></canvas>
        <div class="hud">
            <div class="hud-item">
                <div class="hud-label">Bots Completed</div>
                <div class="hud-value" id="completed">0</div>
            </div>
            <div class="hud-item">
                <div class="hud-label">Elapsed Time</div>
                <div class="hud-value" id="timer">0.0s</div>
            </div>
        </div>
        <button id="reset">RESET GAME</button>
    </div>

    <script>
        const MAZE_SIZE = 21;
        const NUM_BOTS = 24;
        const CANVAS_SIZE = 400;
        const CELL_SIZE = CANVAS_SIZE / MAZE_SIZE;

        const gameState = {
            maze: [],
            bots: [],
            completed: 0,
            tickCount: 0,
            spawn: { x: 1, y: 1 },
            exit: { x: MAZE_SIZE - 2, y: MAZE_SIZE - 2 }
        };

        const canvas = document.getElementById('maze');
        const ctx = canvas.getContext('2d');
        const completedDisplay = document.getElementById('completed');
        const timerDisplay = document.getElementById('timer');
        const resetButton = document.getElementById('reset');

        canvas.width = CANVAS_SIZE;
        canvas.height = CANVAS_SIZE;

        function generateMaze() {
            const maze = Array(MAZE_SIZE).fill(null).map(() => Array(MAZE_SIZE).fill(1));

            function carve(x, y) {
                maze[y][x] = 0;
                const dirs = [[0, -2], [2, 0], [0, 2], [-2, 0]].sort(() => Math.random() - 0.5);
                for (const [dx, dy] of dirs) {
                    const nx = x + dx, ny = y + dy;
                    if (nx > 0 && nx < MAZE_SIZE - 1 && ny > 0 && ny < MAZE_SIZE - 1 && maze[ny][nx]) {
                        maze[y + dy / 2][x + dx / 2] = 0;
                        carve(nx, ny);
                    }
                }
            }

            carve(1, 1);
            maze[gameState.spawn.y][gameState.spawn.x] = 0;
            maze[gameState.exit.y][gameState.exit.x] = 0;
            return maze;
        }

        function findPath(maze, start, end) {
            const queue = [[start.x, start.y, []]];
            const visited = new Set([`${start.x},${start.y}`]);

            while (queue.length) {
                const [x, y, path] = queue.shift();
                if (x === end.x && y === end.y) return path;

                for (const [dx, dy] of [[0, 1], [1, 0], [0, -1], [-1, 0]]) {
                    const nx = x + dx, ny = y + dy, key = `${nx},${ny}`;
                    if (nx >= 0 && nx < MAZE_SIZE && ny >= 0 && ny < MAZE_SIZE &&
                        maze[ny][nx] === 0 && !visited.has(key)) {
                        visited.add(key);
                        queue.push([nx, ny, [...path, { x: nx, y: ny }]]);
                    }
                }
            }
            return [];
        }

        class Bot {
            constructor(id, path) {
                this.id = id;
                this.x = gameState.spawn.x;
                this.y = gameState.spawn.y;
                this.path = path;
                this.pathIndex = 0;
                this.completed = false;
                this.startDelay = id % 2;
            }

            tick() {
                if (this.completed) return;

                if (this.startDelay > 0) {
                    this.startDelay--;
                    return;
                }

                if (this.pathIndex < this.path.length) {
                    const next = this.path[this.pathIndex++];
                    this.x = next.x;
                    this.y = next.y;

                    if (this.pathIndex === this.path.length) {
                        this.completed = true;
                        gameState.completed++;
                    }
                }
            }
        }

        function initGame() {
            gameState.maze = generateMaze();
            const path = findPath(gameState.maze, gameState.spawn, gameState.exit);
            gameState.bots = Array(NUM_BOTS).fill(null).map((_, i) => new Bot(i, path));
            gameState.completed = 0;
            gameState.tickCount = 0;
        }

        function render() {
            ctx.fillStyle = '#000';
            ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

            ctx.fillStyle = '#fff';
            for (let y = 0; y < MAZE_SIZE; y++) {
                for (let x = 0; x < MAZE_SIZE; x++) {
                    if (gameState.maze[y][x]) {
                        ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                    }
                }
            }

            ctx.fillStyle = '#0f0';
            ctx.fillRect(gameState.exit.x * CELL_SIZE, gameState.exit.y * CELL_SIZE, CELL_SIZE, CELL_SIZE);

            ctx.fillStyle = '#00f';
            ctx.fillRect(gameState.spawn.x * CELL_SIZE, gameState.spawn.y * CELL_SIZE, CELL_SIZE, CELL_SIZE);

            gameState.bots.forEach(bot => {
                ctx.fillStyle = bot.completed ? '#0f0' : '#ff0';
                ctx.beginPath();
                ctx.arc((bot.x + 0.5) * CELL_SIZE, (bot.y + 0.5) * CELL_SIZE, CELL_SIZE * 0.35, 0, Math.PI * 2);
                ctx.fill();
            });

            completedDisplay.textContent = gameState.completed;
            const elapsedMs = gameState.tickCount * (1000 / 60);
            timerDisplay.textContent = (elapsedMs / 1000).toFixed(1) + 's';
        }

        function gameLoop() {
            gameState.bots.forEach(bot => bot.tick());
            gameState.tickCount++;
            render();
            requestAnimationFrame(gameLoop);
        }

        resetButton.addEventListener('click', () => {
            initGame();
        });

        window.game = {
            get bots() { return gameState.bots; },
            get completed() { return gameState.completed; },
            get elapsedMs() { return gameState.tickCount * (1000 / 60); },
            tick(n) {
                for (let i = 0; i < n; i++) {
                    gameState.bots.forEach(bot => bot.tick());
                    gameState.tickCount++;
                }
                render();
            },
            reset() { initGame(); }
        };

        initGame();
        gameLoop();
    </script>
</body>
</html>
